import java.io.IOException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        String safeOutput = sanitizeInput(userInput); // Sanitize user input

        response.setContentType("text/html");
        response.getWriter().println("<html><body>");
        response.getWriter().println("<h1>Welcome!</h1>");
        response.getWriter().println("<p>" + safeOutput + "</p>"); // Output sanitized user input
        response.getWriter().println("</body></html>");
    }

    private String sanitizeInput(String userInput) {
        return userInput == null ? "" : userInput.replaceAll("<", "&lt;").replaceAll(">", "&gt;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
